<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Conway's Game of Life</title>
<style>
  :root {
    --bg: #0d1117;
    --panel: #161b22;
    --accent: #39d353;
    --accent2: #58a6ff;
    --text: #c9d1d9;
    --muted: #8b949e;
    --grid-line: #21262d;
    --dead: #0d1117;
  }
  * { box-sizing: border-box; }
  html, body {
    margin: 0;
    padding: 0;
    background: radial-gradient(circle at 50% 0%, #12182200, var(--bg)), var(--bg);
    color: var(--text);
    font-family: "Segoe UI", system-ui, -apple-system, sans-serif;
    min-height: 100vh;
  }
  .wrap {
    max-width: 720px;
    margin: 0 auto;
    padding: 28px 16px 48px;
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 18px;
  }
  h1 {
    margin: 0;
    font-size: 26px;
    font-weight: 700;
    letter-spacing: 0.5px;
    background: linear-gradient(90deg, var(--accent), var(--accent2));
    -webkit-background-clip: text;
    background-clip: text;
    -webkit-text-fill-color: transparent;
  }
  .sub {
    margin: -10px 0 0;
    color: var(--muted);
    font-size: 13px;
  }
  .stage {
    padding: 10px;
    background: var(--panel);
    border: 1px solid var(--grid-line);
    border-radius: 12px;
    box-shadow: 0 12px 40px rgba(0,0,0,0.45), 0 0 0 1px rgba(255,255,255,0.02) inset;
  }
  #life {
    display: block;
    width: 520px;
    height: 520px;
    max-width: 82vw;
    max-height: 82vw;
    border-radius: 8px;
    cursor: crosshair;
    background: var(--dead);
    touch-action: none;
  }
  .controls {
    display: flex;
    flex-wrap: wrap;
    gap: 10px;
    justify-content: center;
  }
  button {
    font: inherit;
    font-size: 14px;
    font-weight: 600;
    color: var(--text);
    background: var(--panel);
    border: 1px solid var(--grid-line);
    padding: 10px 18px;
    border-radius: 8px;
    cursor: pointer;
    transition: transform .08s ease, border-color .15s ease, background .15s ease;
  }
  button:hover { border-color: var(--accent2); background: #1c2330; }
  button:active { transform: translateY(1px) scale(0.98); }
  #play.running {
    border-color: var(--accent);
    background: linear-gradient(180deg, #16321f, #12281a);
    color: var(--accent);
  }
  .meta {
    display: flex;
    gap: 20px;
    color: var(--muted);
    font-size: 13px;
    font-variant-numeric: tabular-nums;
  }
  .meta b { color: var(--text); }
</style>
</head>
<body>
<div class="wrap">
  <h1>Conway's Game of Life</h1>
  <p class="sub">Click or drag to paint cells · B3/S23 · edges are dead</p>
  <div class="stage">
    <canvas id="life" width="520" height="520"></canvas>
  </div>
  <div class="controls">
    <button id="step">Step ▸</button>
    <button id="play">Play ▶</button>
    <button id="random">Random ⚄</button>
    <button id="clear">Clear ✕</button>
  </div>
  <div class="meta">
    <span>Gen: <b id="gen">0</b></span>
    <span>Alive: <b id="alive">0</b></span>
  </div>
</div>
<script>
(function () {
  "use strict";

  const W = 50, H = 50;           // grid dimensions in cells (>= 40)
  const canvas = document.getElementById("life");
  const ctx = canvas.getContext("2d");
  const PX = canvas.width;        // logical canvas px (square)
  const cellSize = PX / W;

  // grid stored as flat array, index = y * W + x
  let grid = new Uint8Array(W * H);
  let generation = 0;

  const genEl = document.getElementById("gen");
  const aliveEl = document.getElementById("alive");

  function idx(x, y) { return y * W + x; }

  function get(x, y) {
    if (x < 0 || y < 0 || x >= W || y >= H) return 0;   // edges are dead
    return grid[idx(x, y)];
  }

  function set(x, y, v) {
    if (x < 0 || y < 0 || x >= W || y >= H) return;
    grid[idx(x, y)] = v ? 1 : 0;
  }

  // Simultaneous B3/S23 update: next state derived from current, applied at once.
  function step() {
    const next = new Uint8Array(W * H);
    for (let y = 0; y < H; y++) {
      for (let x = 0; x < W; x++) {
        let n = 0;
        for (let dy = -1; dy <= 1; dy++) {
          for (let dx = -1; dx <= 1; dx++) {
            if (dx === 0 && dy === 0) continue;
            n += get(x + dx, y + dy);
          }
        }
        const alive = grid[idx(x, y)];
        if (alive) {
          next[idx(x, y)] = (n === 2 || n === 3) ? 1 : 0;
        } else {
          next[idx(x, y)] = (n === 3) ? 1 : 0;
        }
      }
    }
    grid = next;
    generation++;
    draw();
  }

  function clear() {
    grid = new Uint8Array(W * H);
    generation = 0;
    draw();
  }

  function randomize() {
    for (let i = 0; i < grid.length; i++) {
      grid[i] = Math.random() < 0.28 ? 1 : 0;
    }
    generation = 0;
    draw();
  }

  function draw() {
    // background
    ctx.fillStyle = "#0d1117";
    ctx.fillRect(0, 0, PX, PX);

    // live cells with a soft glow
    let count = 0;
    for (let y = 0; y < H; y++) {
      for (let x = 0; x < W; x++) {
        if (grid[idx(x, y)]) {
          count++;
          const px = x * cellSize, py = y * cellSize;
          // hue shifts subtly across the board for playfulness
          const hue = 130 + ((x + y) % 24) * 3;
          ctx.fillStyle = "hsl(" + hue + ", 70%, 55%)";
          ctx.fillRect(px + 0.5, py + 0.5, cellSize - 1, cellSize - 1);
        }
      }
    }

    // grid lines
    ctx.strokeStyle = "rgba(255,255,255,0.04)";
    ctx.lineWidth = 1;
    ctx.beginPath();
    for (let x = 0; x <= W; x++) {
      ctx.moveTo(x * cellSize, 0);
      ctx.lineTo(x * cellSize, PX);
    }
    for (let y = 0; y <= H; y++) {
      ctx.moveTo(0, y * cellSize);
      ctx.lineTo(PX, y * cellSize);
    }
    ctx.stroke();

    genEl.textContent = generation;
    aliveEl.textContent = count;
  }

  // ---- painting ----
  let painting = false;
  let paintValue = 1;

  function cellFromEvent(e) {
    const rect = canvas.getBoundingClientRect();
    const cx = (e.clientX - rect.left) / rect.width * W;
    const cy = (e.clientY - rect.top) / rect.height * H;
    return { x: Math.floor(cx), y: Math.floor(cy) };
  }

  canvas.addEventListener("pointerdown", function (e) {
    e.preventDefault();
    const { x, y } = cellFromEvent(e);
    paintValue = get(x, y) ? 0 : 1;   // toggle based on first cell
    set(x, y, paintValue);
    painting = true;
    canvas.setPointerCapture(e.pointerId);
    draw();
  });

  canvas.addEventListener("pointermove", function (e) {
    if (!painting) return;
    const { x, y } = cellFromEvent(e);
    set(x, y, paintValue);
    draw();
  });

  function endPaint() { painting = false; }
  canvas.addEventListener("pointerup", endPaint);
  canvas.addEventListener("pointercancel", endPaint);

  // ---- controls ----
  let timer = null;
  const playBtn = document.getElementById("play");

  function togglePlay() {
    if (timer) {
      clearInterval(timer);
      timer = null;
      playBtn.textContent = "Play ▶";
      playBtn.classList.remove("running");
    } else {
      timer = setInterval(step, 90);
      playBtn.textContent = "Pause ⏸";
      playBtn.classList.add("running");
    }
  }

  document.getElementById("step").addEventListener("click", step);
  playBtn.addEventListener("click", togglePlay);
  document.getElementById("random").addEventListener("click", randomize);
  document.getElementById("clear").addEventListener("click", clear);

  // ---- seed a friendly glider so it's fun on load ----
  set(1, 0, 1); set(2, 1, 1); set(0, 2, 1); set(1, 2, 1); set(2, 2, 1);
  draw();

  // ---- programmatic API ----
  window.life = {
    w: W,
    h: H,
    get: get,
    set: function (x, y, v) { set(x, y, v); draw(); },
    step: step,
    clear: clear,
  };
})();
</script>
</body>
</html>
